\[
\begin{aligned}
C &= c_0 + \sum_{l=1}^L c_l n_l \\
&= c_0 + \sum_{l=1}^L c_l \times \color{red}{n} \ \frac{\omega_l \sigma_l /\sqrt{c_l}}{\sum_{k=1}^L \omega_k \sigma_k  /\sqrt{c_k}}
